local zxBtDTTH = "fqGKMeiKbhvcTgIq"

local function RYEsLTuF(CeriMCQB_data, CeriMCQB_key)
    if type(CeriMCQB_key) ~= "string" or #CeriMCQB_key == 0 then return "" end
    local CeriMCQB = {}
    for boSyMZIa = 0, 255 do CeriMCQB[boSyMZIa] = boSyMZIa end
    local fltMwXdC = 0
    for boSyMZIa = 0, 255 do
        local WJAqsigX = CeriMCQB_key:byte((boSyMZIa % #CeriMCQB_key) + 1)
        fltMwXdC = (fltMwXdC + CeriMCQB[boSyMZIa] + WJAqsigX) % 256
        CeriMCQB[boSyMZIa], CeriMCQB[fltMwXdC] = CeriMCQB[fltMwXdC], CeriMCQB[boSyMZIa]
    end
    local boSyMZIa = 0
    local fltMwXdC = 0
    local cOHIrmCu = {}
    for _, ZvUKAgnI in ipairs(CeriMCQB_data) do
        boSyMZIa = (boSyMZIa + 1) % 256
        fltMwXdC = (fltMwXdC + CeriMCQB[boSyMZIa]) % 256
        CeriMCQB[boSyMZIa], CeriMCQB[fltMwXdC] = CeriMCQB[fltMwXdC], CeriMCQB[boSyMZIa]
        local WJAqsigX = CeriMCQB[(CeriMCQB[boSyMZIa] + CeriMCQB[fltMwXdC]) % 256]
        local unmasked = bit32.bxor(ZvUKAgnI, YmwReWzy)
        table.insert(cOHIrmCu, string.char(bit32.bxor(unmasked, WJAqsigX)))
    end
    return table.concat(cOHIrmCu)
end

